#include <iostream>\n#include <vector>\n\nclass Graph {\n public:\n  explicit Graph(int n) : n_(n), comps_count_(n) {\n    p_.resize(n_);\n    r_.resize(n_, 0);\n    for (int i = 0; i < n; i++) {\n      p_[i] = i;\n    }\n  }\n\n  void AddEdge(int a, int b) {\n    a = Get(a);\n    b = Get(b);\n    edge_count_++;\n    if (a != b) {\n      Union(a, b);\n      comps_count_--;\n    }\n  }\n\n  bool IsOneComp() {\n    return comps_count_ == 1;\n  }\n\n  int GetEdgeCount() {\n    return edge_count_;\n  }\n\n private:\n  void Union(int a, int b) {  // передаём корни, Get не нужен\n    if (r_[a] > r_[b]) {\n      std::swap(a, b);\n    }\n    if (r_[a] == r_[b]) {\n      r_[b]++;\n    }\n    p_[a] = b;\n  }\n\n  int Get(int a) {\n    if (p_[a] != a) {\n      p_[a] = Get(p_[a]);\n    }\n    return p_[a];\n  }\n\n  int edge_count_ = 0;\n  int n_;\n  int comps_count_;\n  std::vector<int> p_;\n  std::vector<int> r_;\n};\n\nint main() {\n  int n = 0;\n  int m = 0;\n  std::cin >> n >> m;\n\n  Graph g(n);\n\n  for (int i = 0; i < m; i++) {\n    int a = 0;\n    int b = 0;\n    std::cin >> a >> b;\n    g.AddEdge(a, b);\n    if (g.IsOneComp()) {\n      break;\n    }\n  }\n  std::cout << g.GetEdgeCount() << std::endl;\n  return 0;\n}